from collections import deque

def main():
    N, K = map(int, sys.stdin.readline().split())
    A = list(map(int, sys.stdin.readline().split()))
    A = [a - 1 for a in A]

    if K == 1:
        # Special case: all must point to capital
        changes = 0
        for i in range(N):
            if A[i] != 0:
                changes += 1
        print(changes)
        return

    # Build graph and find depth from capital using BFS
    graph = [[] for _ in range(N)]
    for i in range(N):
        graph[A[i]].append(i)

    depth = [-1] * N
    depth[0] = 0
    queue = deque([0])
    while queue:
        u = queue.popleft()
        for v in graph[u]:
            if depth[v] == -1:
                depth[v] = depth[u] + 1
                queue.append(v)

    changes = 0
    if A[0] != 0:
        changes += 1
        A[0] = 0

    # For each node, if depth > K-1, we need to change its teleporter
    # If depth == K-1, it should point to capital
    for i in range(1, N):
        if depth[i] >= K:
            changes += 1
        elif depth[i] == K - 1:
            if A[i] != 0:
                changes += 1

    print(changes)

