    # Make it a list for easy modification
    s = list(S)
    n = len(s)

    # Greedily go from left to right
    # Whenever we see a '1', we must flip the segment starting at this position
    i = 0
    while i < n:
        if s[i] == '1':
            # Flip the segment starting at i with length min(K, n-i)
            end = min(i + K, n)
            for j in range(i, end):
                s[j] = '1' if s[j] == '0' else '0'
        i += 1

    # Check if we made all zeros
    return all(c == '0' for c in s)

